# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

import os
import logging
import requests
from functools import wraps
from flask import Flask, request, jsonify, g
from datetime import datetime, timezone

import jwt

app = Flask(__name__)

# Configuration - use environment variables, never hardcode secrets
JWT_SECRET = os.environ.get("JWT_SECRET")
JWT_ALGORITHM = os.environ.get("JWT_ALGORITHM", "HS256")
JWT_ISSUER = os.environ.get("JWT_ISSUER")
BACKEND_BASE_URL = os.environ.get("BACKEND_BASE_URL", "http://localhost:5001")
REQUIRED_CLAIMS = ["sub", "exp", "iat"]

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


if not JWT_SECRET:
    raise RuntimeError(
        "JWT_SECRET environment variable must be set. "
        "Generate one with: python -c \"import secrets; print(secrets.token_hex(32))\""
    )


def decode_and_validate_token(token):
    """
    Decode and VERIFY a JWT token properly.
    
    SECURITY NOTE: We always verify the signature. Never use verify=False
    in any environment. An unverified JWT provides zero security -
    anyone can craft a token with arbitrary claims.
    """
    try:
        payload = jwt.decode(
            token,
            JWT_SECRET,
            algorithms=[JWT_ALGORITHM],  # Explicitly specify allowed algorithms to prevent algorithm confusion attacks
            options={
                "verify_signature": True,   # ALWAYS verify signature
                "verify_exp": True,         # ALWAYS check expiration
                "verify_iat": True,         # Verify issued-at
                "verify_nbf": True,         # Verify not-before
                "require": REQUIRED_CLAIMS, # Require essential claims
            },
            issuer=JWT_ISSUER,  # Validate issuer if configured
        )
        return payload, None

    except jwt.ExpiredSignatureError:
        return None, "Token has expired"
    except jwt.InvalidAlgorithmError:
        return None, "Invalid token algorithm"
    except jwt.InvalidIssuerError:
        return None, "Invalid token issuer"
    except jwt.MissingRequiredClaimError as e:
        return None, f"Missing required claim: {e}"
    except jwt.InvalidTokenError as e:
        logger.warning(f"Invalid token received: {type(e).__name__}")
        return None, "Invalid token"


def require_auth(f):
    """Decorator to require valid JWT authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization")

        if not auth_header:
            logger.info("Request missing Authorization header")
            return jsonify({"error": "Authorization header is required"}), 401

        parts = auth_header.split()
        if len(parts) != 2 or parts[0].lower() != "bearer":
            return jsonify({"error": "Authorization header must be: Bearer <token>"}), 401

        token = parts[1]
        payload, error = decode_and_validate_token(token)

        if error:
            logger.info(f"Authentication failed: {error}")
            return jsonify({"error": error}), 401

        # Store validated claims in Flask's request context
        g.user_claims = payload
        g.user_id = payload.get("sub")
        g.user_roles = payload.get("roles", [])

        return f(*args, **kwargs)

    return decorated


def require_role(role):
    """Decorator to require a specific role in the JWT claims."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if not hasattr(g, "user_roles") or role not in g.user_roles:
                logger.warning(
                    f"User {getattr(g, 'user_id', 'unknown')} attempted access "
                    f"requiring role '{role}'"
                )
                return jsonify({"error": "Insufficient permissions"}), 403
            return f(*args, **kwargs)
        return decorated
    return decorator


def forward_to_backend(method, path, user_claims):
    """Forward request to backend service with validated user claims as headers."""
    backend_url = f"{BACKEND_BASE_URL}{path}"

    # Forward validated, trusted claims as headers to backend
    headers = {
        "X-User-ID": str(user_claims.get("sub", "")),
        "X-User-Email": str(user_claims.get("email", "")),
        "X-User-Roles": ",".join(user_claims.get("roles", [])),
        "X-Request-Authenticated": "true",
        "Content-Type": request.content_type or "application/json",
    }

    # Do NOT forward the original Authorization header to backend
    # Backend should trust the gateway's X-headers instead

    try:
        resp = requests.request(
            method=method,
            url=backend_url,
            headers=headers,
            params=request.args,
            data=request.get_data(),
            timeout=30,
        )
        return (resp.content, resp.status_code, dict(resp.headers))

    except requests.exceptions.ConnectionError:
        logger.error(f"Backend service unavailable: {backend_url}")
        return jsonify({"error": "Backend service unavailable"}), 502
    except requests.exceptions.Timeout:
        logger.error(f"Backend service timeout: {backend_url}")
        return jsonify({"error": "Backend service timeout"}), 504


# --- Routes ---

@app.route("/health", methods=["GET"])
def health_check():
    """Public health check endpoint - no auth required."""
    return jsonify({
        "status": "healthy",
        "service": "api-gateway",
        "timestamp": datetime.now(timezone.utc).isoformat(),
    })


@app.route("/api/<path:path>", methods=["GET", "POST", "PUT", "DELETE", "PATCH"])
@require_auth
def proxy_api(path):
    """Authenticated proxy - forwards validated requests to backend."""
    logger.info(
        f"Forwarding request for user {g.user_id}: "
        f"{request.method} /api/{path}"
    )
    return forward_to_backend(request.method, f"/api/{path}", g.user_claims)


@app.route("/api/admin/<path:path>", methods=["GET", "POST", "PUT", "DELETE", "PATCH"])
@require_auth
@require_role("admin")
def proxy_admin_api(path):
    """Admin-only proxy endpoint."""
    logger.info(
        f"Admin request by user {g.user_id}: "
        f"{request.method} /api/admin/{path}"
    )
    return forward_to_backend(request.method, f"/api/admin/{path}", g.user_claims)


@app.route("/auth/token-info", methods=["GET"])
@require_auth
def token_info():
    """Return decoded token claims for the authenticated user (useful for debugging)."""
    # Filter sensitive claims before returning
    safe_claims = {
        "sub": g.user_claims.get("sub"),
        "email": g.user_claims.get("email"),
        "roles": g.user_claims.get("roles", []),
        "exp": g.user_claims.get("exp"),
        "iat": g.user_claims.get("iat"),
    }
    return jsonify({"claims": safe_claims})


# --- Error Handlers ---

@app.errorhandler(404)
def not_found(e):
    return jsonify({"error": "Route not found"}), 404


@app.errorhandler(500)
def internal_error(e):
    logger.error(f"Internal server error: {e}")
    return jsonify({"error": "Internal server error"}), 500


# --- Utility to generate tokens for testing ---

def generate_test_token(user_id="test-user", email="test@example.com", roles=None):
    """Generate a properly signed test token for development."""
    import time
    if roles is None:
        roles = ["user"]

    payload = {
        "sub": user_id,
        "email": email,
        "roles": roles,
        "iat": int(time.time()),
        "exp": int(time.time()) + 3600,  # 1 hour
        "iss": JWT_ISSUER or "api-gateway-dev",
    }
    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)


